sql:
SELECT sol, AVG(avg_temp) AS average_temperature
FROM rovers_data
GROUP BY sol;

SELECT COUNT(mission_id) AS active_missions
FROM missions
WHERE mission_status = 'active';

SELECT mission_status, SUM(budget) AS total_budget, AVG(total_data_collected) AS avg_data_collected
FROM missions
GROUP BY mission_status;

SELECT AVG(budget) AS average_budget
FROM missions
WHERE mission_status = 'active';

SELECT rover_name, AVG(total_data_sent) AS average_data_sent
FROM rovers
GROUP BY rover_name;

SELECT COUNT(rover_id)
FROM rovers
WHERE status = 'active';

SELECT mission_name
FROM missions
WHERE total_data_collected = (SELECT MAX(total_data_collected) FROM missions);

external_knowledge:
- 'explorers' refers to rovers and landers;
- 'highest temperature' corresponds to the maximum value of the 'max_temp' column;
- 'active' indicates the status of the rovers that are currently operational.

